#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

bool isPalindrome(string text)
{
    string cleaned;
    for (char c : text)
    {
        if (c != ' ')
        {
            cleaned += tolower(c);
        }
    }

    string reversed = cleaned;
    reverse(reversed.begin(), reversed.end());

    return cleaned == reversed;
}

bool isNumberPalindrome(int number)
{
    string text = to_string(number);
    string reversed = text;
    reverse(reversed.begin(), reversed.end());
    return text == reversed;
}

int main()
{
    string words[] = {"kayak", "araba", "anna", "elma", "a man a plan a canal panama"};

    cout << "Kelime testleri:" << endl;
    for (const string& word : words)
    {
        cout << "'" << word << "' palindrome mu: " << isPalindrome(word) << endl;
    }

    cout << "\nSayi testleri:" << endl;
    int numbers[] = {12321, 12345, 1001, 5};
    for (int num : numbers)
    {
        cout << num << " palindrome mu: " << isNumberPalindrome(num) << endl;
    }

    return 0;
}
